import{_ as a,o as n,c as s,ae as t}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Firebase Configuration","description":"","frontmatter":{"title":"Firebase Configuration","slug":"firebase-configuration"},"headers":[],"relativePath":"developer-hub/firebase-configuration.md","filePath":"developer-hub/firebase-configuration.md"}'),i={name:"developer-hub/firebase-configuration.md"};function o(r,e,l,p,c,u){return n(),s("div",null,[...e[0]||(e[0]=[t(`<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With a push of a button, you can send your Branch data to your Google Analytics dashboard, helping you understand the power of Branch as an acquisition pathway. If you&#39;re interested in the segment of users coming into your apps through Branch and want to measure their events against your other cohorts, this guide can help.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and completing the relevant code will result in Branch automatically forwarding referred events to Google Firebase, in the exact format Firebase expects.</p><h3 id="branch-events-sent-to-firebase" tabindex="-1">Branch Events Sent to Firebase <a class="header-anchor" href="#branch-events-sent-to-firebase" aria-label="Permalink to &quot;Branch Events Sent to Firebase&quot;">​</a></h3><p>Branch will send <em>referred</em> <strong>installs</strong>, <strong>opens</strong>, <strong>commerce</strong>, <strong>content</strong>, <strong>user lifecycle</strong> as well as any <strong>custom events</strong> you track with Branch. Non-referred events, clicks, web session starts, and pageviews will be excluded. Branch also sends over analytics data that is attached to the link, whether it&#39;s UTM tags or fields set in Branch (e.g. Campaign, Channel, Feature). This will allow you to analyze which campaigns, channels, etc. are helping you acquire and engage users.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Firebase, you need to have completed the following:</p><ol><li><p>Admin access to <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="https://firebase.google.com/docs/guides" target="_blank" rel="noreferrer">Firebase Analytics SDK</a></p></li><li><p>Admin access to your Firebase account.</p></li></ol><h2 id="enable-firebase" tabindex="-1">Enable Firebase <a class="header-anchor" href="#enable-firebase" aria-label="Permalink to &quot;Enable Firebase&quot;">​</a></h2><p>The code snippets below should be called before you track events via the Firebase SDK. This will not change event counts in Firebase, but rather allows you to augment those Firebase calls with Branch attribution data, when that data is available (i.e., the session or event would&#39;ve been attributed in Branch). A few things to be aware of when passing this data through:</p><ul><li>Branch tracks one INSTALL event per user. You can check if <code>+is_first_session</code> is &quot;true&quot; in Branch&#39;s SDK callback, to confirm if the session will be tracked as an INSTALL in Branch.</li><li>Branch frequency caps non-referred OPENs (i.e., OPENS that were not sourced via a deep link), so session counts between Branch &amp; Firebase will not be the same (ask your account manager for your app&#39;s frequency cap). Attribution data will still be accessible in app, even if the session won&#39;t be tracked in Branch.</li></ul><h2 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h2><ol><li>Ensure you&#39;ve completed the Firebase SDK implementation as documented <a href="https://firebase.google.com/docs/analytics/android/start" target="_blank" rel="noreferrer">here</a></li><li>Ensure you&#39;ve completed the Branch SDK implementation as documented <a href="./android-sdk-overview.html">here</a>.</li><li>In the <code>LauncherActivity#onStart() method</code> of the Branch Android SDK, update the implementation as below:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.getInstance().getLastAttributedTouchData(</span></span>
<span class="line"><span>                new ServerRequestGetLATD.BranchLastAttributedTouchDataListener() {</span></span>
<span class="line"><span>                    @Override</span></span>
<span class="line"><span>                    public void onDataFetched(JSONObject jsonObject, BranchError error) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                        if (error == null) {</span></span>
<span class="line"><span>                            if (jsonObject != null) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                FirebaseAnalytics firebaseAnalytics = FirebaseAnalytics</span></span>
<span class="line"><span>                                        .getInstance(getApplicationContext());</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                Bundle bundle = new Bundle();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                try {</span></span>
<span class="line"><span>                                    JSONObject latd = jsonObject.getJSONObject(&quot;last_attributed_touch_data&quot;).getJSONObject(&quot;data&quot;);</span></span>
<span class="line"><span>                                    String feature = latd.getString(&quot;~feature&quot;);</span></span>
<span class="line"><span>                                    String channel = latd.getString(&quot;~channel&quot;);</span></span>
<span class="line"><span>                                    String campaign = latd.getString(&quot;~campaign&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                        bundle.putString(&quot;utm_medium&quot;, feature);</span></span>
<span class="line"><span>                                        bundle.putString(&quot;utm_source&quot;, channel);</span></span>
<span class="line"><span>                                        bundle.putString(&quot;utm_campaign&quot;, campaign);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                    firebaseAnalytics.logEvent(&quot;custom_event&quot;, bundle);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                } catch (JSONException ignore) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                            }</span></span>
<span class="line"><span>                        }</span></span>
<span class="line"><span>                    }</span></span>
<span class="line"><span>                }, 30);</span></span></code></pre></div><h2 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h2><ol><li>Ensure you&#39;ve completed the Firebase SDK implementation as documented <a href="https://firebase.google.com/docs/analytics/ios/start" target="_blank" rel="noreferrer">here</a></li><li>Ensure you&#39;ve completed the Branch SDK implementation as documented <a href="./ios-sdk-overview.html">here</a>.</li><li>In the <code>AppDelegate</code> of the Branch iOS SDK, update the implementation as below:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.getInstance().lastAttributedTouchData(withAttributionWindow: 30) { latd in</span></span>
<span class="line"><span>            guard let json = latd?.lastAttributedTouchJSON else { return }</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>                if let params = json[&quot;data&quot;] as? NSDictionary {</span></span>
<span class="line"><span>                var firebaseParams = [String: Any]()</span></span>
<span class="line"><span>                firebaseParams[&quot;utm_campaign&quot;] = params[&quot;~campaign&quot;] ?? &quot;&quot;</span></span>
<span class="line"><span>                // get the link feature</span></span>
<span class="line"><span>                firebaseParams[&quot;utm_medium&quot;] = params[&quot;~feature&quot;] ?? &quot;&quot;</span></span>
<span class="line"><span>                // get the link channel</span></span>
<span class="line"><span>                firebaseParams[&quot;utm_source&quot;] = params[&quot;~channel&quot;] ?? &quot;&quot;</span></span>
<span class="line"><span>                // get the link term</span></span>
<span class="line"><span>                firebaseParams[&quot;utm_term&quot;] = params[&quot;~keyword&quot;] ?? &quot;&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                Analytics.logEvent(&quot;custom_event&quot;, parameters: firebaseParams)</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">mParticle for Android and/or iOS</p><p>If you use the mParticle plugins alongside the Branch SDK, you must <strong>ensure Firebase authenticates before the Branch session is initialized with mParticle</strong>. When the Branch session is initialized with mParticle prior to Firebase authentication, the deep link data is not returned.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h2 id="using-firebase-debugview" tabindex="-1">Using Firebase DebugView <a class="header-anchor" href="#using-firebase-debugview" aria-label="Permalink to &quot;Using Firebase DebugView&quot;">​</a></h2><p>To debug the events and their metadata, you can enable the <code>DebugView</code> on Firebase to verify the setup. Please refer to Google&#39;s official instructions <a href="https://firebase.google.com/docs/analytics/debugview" target="_blank" rel="noreferrer">here</a>.</p><h2 id="common-discrepancies-between-firebase-branch" tabindex="-1">Common Discrepancies Between Firebase &amp; Branch <a class="header-anchor" href="#common-discrepancies-between-firebase-branch" aria-label="Permalink to &quot;Common Discrepancies Between Firebase &amp; Branch&quot;">​</a></h2><ul><li><p>When the attribution of the custom events occurs in the following sessions after the click (i.e not the session after the immediate click). For example, Click -&gt; app open -&gt; app close -&gt; app open -&gt; Purchase -&gt; Purchase sent to Firebase.</p><p>The above purchase event on Branch might be attributed based on the attribution window, but on the Firebase this will always be organic as the SDK will not have the attribution data.</p></li><li><p>SAN attribution support, for Google UAC (no deep linking) and Facebook App Install (not so reliable deferred deep links), the Firebase installs would miss the attribution data.</p></li></ul><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Please ensure you’ve reviewed your agreements with any ad network (for example Facebook, Snap and Twitter) to ensure your handling of attribution data and use of third party analytics tools is in compliance.</p></div><ul><li>As per your account settings, it may be the case where attribution via probabilistic modeling is disabled. This means that the deep link will return the link data, but no attribution data will be recorded at Branch’s end. If this is the case (ensure to check with your Account Manager).</li></ul>`,27)])])}const b=a(i,[["render",o]]);export{d as __pageData,b as default};
